from flask import Flask, request, jsonify
from collections import defaultdict, Counter
from threading import Lock
import os
from werkzeug.utils import secure_filename
from PIL import Image
import numpy as np
from sklearn.linear_model import LogisticRegression

app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = 'uploads'
os.makedirs(app.config['UPLOAD_FOLDER'], exist_ok=True)

lock = Lock()
image_labels = defaultdict(list)
model = LogisticRegression()

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in {'png', 'jpg', 'jpeg'}

@app.route('/upload', methods=['POST'])
def upload_image():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        file.save(filepath)
        return jsonify({'message': 'File uploaded successfully'}), 200
    return jsonify({'error': 'Invalid file type'}), 400

@app.route('/label', methods=['POST'])
def label_image():
    data = request.json
    image_id = data.get('image_id')
    label = data.get('label')
    if not image_id or not label:
        return jsonify({'error': 'Invalid data'}), 400
    with lock:
        image_labels[image_id].append(label)
    return jsonify({'message': 'Label received'}), 200

@app.route('/aggregate', methods=['GET'])
def aggregate_labels():
    aggregated_labels = {}
    with lock:
        for image_id, labels in image_labels.items():
            most_common_label = Counter(labels).most_common(1)[0][0]
            aggregated_labels[image_id] = most_common_label
    return jsonify(aggregated_labels), 200

@app.route('/train', methods=['POST'])
def train_model():
    X, y = [], []
    with lock:
        for image_id, label in image_labels.items():
            filepath = os.path.join(app.config['UPLOAD_FOLDER'], image_id)
            if os.path.exists(filepath):
                image = Image.open(filepath)
                image_array = np.array(image).flatten()
                X.append(image_array)
                y.append(Counter(label).most_common(1)[0][0])
    if X and y:
        model.fit(X, y)
        return jsonify({'message': 'Model trained successfully'}), 200
    return jsonify({'error': 'No data to train on'}), 400

if __name__ == '__main__':
    app.run(debug=False)